 * 
 * @param points Initial array of points.
 * @param target The target point.
 * @return int64_t The minimum generation step k, or -1 if unreachable.
 */
int64_t solve(const std::vector<std::vector<int64_t>>& points, const std::vector<int64_t>& target) {

    // 1. Initialization: Store available points in a set for fast lookup and uniqueness.
    std::set<Point, PointComparator> available_points_set;
    for (const auto& p : points) {
        available_points_set.insert(p);
    }

    // Check initial generation (k=0)
    if (available_points_set.count(target)) {
        return 0;
    }

    int64_t k = 0;

    // Loop generation by generation
    while (true) {
        k++;

        std::set<Point, PointComparator> new_points_set;

        // Convert set to vector to allow indexed iteration for pairwise comparison
        std::vector<Point> available_points(available_points_set.begin(), available_points_set.end());
        int N = available_points.size();

        // Generate new points by pairing distinct available points
        for (int i = 0; i < N; ++i) {
            for (int j = i + 1; j < N; ++j) {
                const Point& a = available_points[i];
                const Point& b = available_points[j];

                Point c(3);

                // Calculate c = [floor((x1 + x2) / 2), ...]
                // Since coordinates are non-negative, integer division handles floor correctly.
                c[0] = (a[0] + b[0]) / 2;
                c[1] = (a[1] + b[1]) / 2;
                c[2] = (a[2] + b[2]) / 2;

                new_points_set.insert(c);
            }
        }

        // Check if any new points were generated
        if (new_points_set.empty()) {
            // No new points, target unreachable
            return -1;
        }

        // Check if target was generated in this step (generation k)
        if (new_points_set.count(target)) {
            return k;
        }

        // Update the set of available points for the next generation
        for (const auto& p : new_points_set) {
            available_points_set.insert(p);
        }

        // Safety break for extreme cases, although convergence should happen much faster
        // Given the constraints (0-6), max points is 343. 
        if (k > 400) return -1; 
    }
}

